{
  "name": "Medimart AI",
  "description": "A conversational medical assistant that can analyze medical documents, provide medicine-related guidance, and locate healthcare providers. It uses Gemini for advanced reasoning and multi-modal analysis.",
  "requestFramePermissions": [
    "camera",
    "microphone",
    "geolocation"
  ]
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Message, Doctor, FilterCriteria } from './types';
import { ChatInput } from './components/ChatInput';
import { ChatMessage } from './components/ChatMessage';
import { runQuery, findDoctors as findDoctorsService, translateToAssamese, generateComparisonImage } from './services/geminiService';
import { MapPinIcon } from './components/icons/MapPinIcon';
import { FilterModal } from './components/FilterModal';
import { SmileIcon } from './components/icons/SmileIcon';
import { SuggestionModal } from './components/SuggestionModal';
import { LightbulbIcon } from './components/icons/LightbulbIcon';
import { ImageViewerModal } from './components/ImageViewerModal';
import { CameraVoiceAssistant } from './components/CameraVoiceAssistant';
import { CameraIcon } from './components/icons/CameraIcon';

// FIX: Fix TypeScript error for subsequent property declarations by moving the interface into the global scope.
declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }

  interface Window {
    aistudio?: AIStudio;
  }
}

const generateUniqueId = () => `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

const App: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    {
      id: generateUniqueId(),
      role: 'model',
      parts: [{ text: "Hello! I'm Medimart AI, your friendly medical assistant. How can I help you today? You can ask me about medications, upload a prescription, or ask me to find a doctor nearby." }],
      timestamp: new Date(),
    },
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const [isFilterModalOpen, setIsFilterModalOpen] = useState(false);
  const [isSuggestionModalOpen, setIsSuggestionModalOpen] = useState(false);
  const [isVoiceAssistantOpen, setIsVoiceAssistantOpen] = useState(false);
  const [viewingImage, setViewingImage] = useState<string | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = useCallback(async (text: string, file: File | null) => {
    if (!text && !file) return;

    setIsLoading(true);

    const userMessage: Message = {
      id: generateUniqueId(),
      role: 'user',
      parts: [{ text }],
      timestamp: new Date(),
    };

    if (file) {
      userMessage.file = file;
    }

    setMessages(prev => [...prev, userMessage]);

    const placeholderId = generateUniqueId();
    setMessages(prev => [...prev, { id: placeholderId, role: 'model', parts: [{ text: '' }], timestamp: new Date(), isLoading: true }]);

    try {
      const stream = await runQuery(text, file);

      let fullResponse = '';
      for await (const chunk of stream) {
        const chunkText = chunk.text;
        fullResponse += chunkText;
        setMessages(prev => prev.map(msg => 
            msg.id === placeholderId ? { ...msg, parts: [{ text: fullResponse }], isLoading: false } : msg
        ));
      }

    } catch (error) {
      console.error('Error from Gemini API:', error);
      let errorText = 'Sorry, I encountered an error. Please try again.';
       if (error instanceof Error && error.message.toLowerCase().includes('permission')) {
          errorText = 'There seems to be an API permission issue. Please ensure the API key is configured correctly.';
       }
      const errorMessage: Message = {
        id: generateUniqueId(),
        role: 'model',
        parts: [{ text: errorText }],
        timestamp: new Date(),
      };
      setMessages(prev => prev.map(msg => msg.id === placeholderId ? errorMessage : msg));
    } finally {
      setIsLoading(false);
    }
  }, []);

  const handleSearchWithFilters = useCallback((filters: FilterCriteria) => {
    setIsFilterModalOpen(false);

    let userQuery = "Searching for doctors";
    const queryParts: string[] = [];
    if(filters.doctorName) queryParts.push(`named ${filters.doctorName}`);
    if(filters.hospitalName) queryParts.push(`at ${filters.hospitalName}`);
    if (filters.specialty) {
        queryParts.push(`specializing in ${filters.specialty}`);
    }
    if (filters.location) {
        queryParts.push(`in ${filters.location}`);
    } else if (!filters.doctorName && !filters.hospitalName) {
         queryParts.push(`near me`);
    }

    if(queryParts.length > 0) {
      userQuery += ` ${queryParts.join(' ')}`;
    }
    userQuery += '...';


    const userMessage: Message = { id: generateUniqueId(), role: 'user', parts: [{ text: userQuery }], timestamp: new Date() };
    const loadingMessageId = generateUniqueId();
    const loadingMessage: Message = { id: loadingMessageId, role: 'model', parts: [{ text: '' }], timestamp: new Date(), isLoading: true };
    setMessages(prev => [...prev, userMessage, loadingMessage]);

    const performSearch = async (latitude: number | null, longitude: number | null) => {
        setIsLoading(true);
        try {
            const { doctors, groundingChunks } = await findDoctorsService(latitude, longitude, filters);

            if (doctors && doctors.length > 0) {
                const successMessage: Message = {
                    id: generateUniqueId(),
                    role: 'model',
                    parts: [{ text: "Here are some highly-rated doctors I found for you by searching our network, including trusted partners like PharmEasy:" }],
                    timestamp: new Date(),
                    doctors: doctors,
                    groundingChunks: groundingChunks,
                };
                setMessages(prev => prev.map(msg => msg.id === loadingMessageId ? successMessage : msg));
            } else if (doctors) { // doctors is an empty array
                const noResultsMessage: Message = {
                    id: generateUniqueId(),
                    role: 'model',
                    parts: [{ text: "I searched, but I couldn't find any doctors matching your specific criteria. You might want to try different filters." }],
                    timestamp: new Date(),
                };
                 setMessages(prev => prev.map(msg => msg.id === loadingMessageId ? noResultsMessage : msg));
            }
            else { // doctors is null
                throw new Error("Could not find doctors or response was invalid.");
            }
        } catch (error: any) {
            console.error('Error finding doctors:', error);
            let errorText = 'Sorry, I had trouble finding doctors with those filters. The feature might be unavailable for that location or criteria. Please try again later.';
            if (error.message?.toLowerCase().includes('permission')) {
                errorText = 'There seems to be an API permission issue. Please ensure the API key is configured correctly.';
            }
            const errorMessage: Message = {
                id: generateUniqueId(),
                role: 'model',
                parts: [{ text: errorText }],
                timestamp: new Date(),
            };
            setMessages(prev => prev.map(msg => msg.id === loadingMessageId ? errorMessage : msg));
        } finally {
            setIsLoading(false);
        }
    };

    if (filters.location || filters.doctorName || filters.hospitalName) {
        performSearch(null, null);
    } else {
        navigator.geolocation.getCurrentPosition(
            (position) => {
                performSearch(position.coords.latitude, position.coords.longitude);
            },
            (error) => {
                console.error('Geolocation error:', error);
                let errorText = 'I need your location to find nearby doctors. Please enable location services or enter a location manually in the filter options.';
                if (error.code === error.PERMISSION_DENIED) {
                    errorText = "I can't find doctors without your location. Please grant permission or enter a location manually and try again.";
                }
                const errorMessage: Message = {
                    id: generateUniqueId(),
                    role: 'model',
                    parts: [{ text: errorText }],
                    timestamp: new Date(),
                };
                setMessages(prev => prev.map(msg => msg.id === loadingMessageId ? errorMessage : msg));
                setIsLoading(false);
            }
        );
    }
  }, []);

 const handleTranslate = useCallback(async (messageId: string, text: string) => {
    setMessages(prev =>
      prev.map(msg =>
        msg.id === messageId ? { ...msg, isTranslating: true } : msg
      )
    );
    try {
      const translatedText = await translateToAssamese(text);
      setMessages(prev =>
        prev.map(msg =>
          msg.id === messageId
            ? { ...msg, translatedText, isTranslating: false }
            : msg
        )
      );
    } catch (error) {
      console.error('Translation failed:', error);
      setMessages(prev =>
        prev.map(msg =>
          msg.id === messageId ? { ...msg, isTranslating: false, translatedText: "Translation failed." } : msg
        )
      );
    }
  }, []);

  const handleSuggestionSearch = useCallback(async (query: string) => {
    setIsSuggestionModalOpen(false);
    setIsLoading(true);

    const userMessage: Message = {
      id: generateUniqueId(),
      role: 'user',
      parts: [{ text: `Generate a comparison for: ${query}` }],
      timestamp: new Date(),
    };

    const loadingMessageId = generateUniqueId();
    const loadingMessage: Message = {
      id: loadingMessageId,
      role: 'model',
      parts: [{ text: 'Generating your custom comparison image...' }],
      timestamp: new Date(),
      isLoading: true,
    };
    setMessages(prev => [...prev, userMessage, loadingMessage]);

    try {
      const { image: imageBase64, error: generationError } = await generateComparisonImage(query);

      if (imageBase64) {
        const successMessage: Message = {
          id: generateUniqueId(),
          role: 'model',
          parts: [{ text: `Here is the visual comparison for "${query}":` }],
          timestamp: new Date(),
          comparisonImage: imageBase64,
        };
        setMessages(prev => prev.map(msg => msg.id === loadingMessageId ? successMessage : msg));
      } else {
         const errorMessageText = generationError || `I'm sorry, I couldn't generate a comparison for "${query}". Please check the product names and try again.`;
        const errorMessage: Message = {
          id: generateUniqueId(),
          role: 'model',
          parts: [{ text: errorMessageText }],
          timestamp: new Date(),
        };
        setMessages(prev => prev.map(msg => msg.id === loadingMessageId ? errorMessage : msg));
      }

    } catch (error: any) {
      console.error("Failed to generate comparison image:", error);
       let errorText = 'An unexpected error occurred while generating the image.';
       if (error.message?.toLowerCase().includes('permission')) {
          errorText = 'There seems to be an API permission issue. Please ensure the API key is configured correctly.';
       }
      const errorMessage: Message = {
        id: generateUniqueId(),
        role: 'model',
        parts: [{ text: errorText }],
        timestamp: new Date(),
      };
      setMessages(prev => prev.map(msg => msg.id === loadingMessageId ? errorMessage : msg));
    } finally {
      setIsLoading(false);
    }
  }, []);

  const handleImageView = (imageSrc: string) => {
    setViewingImage(imageSrc);
  };

  return (
    <>
      <FilterModal 
        isOpen={isFilterModalOpen}
        onClose={() => setIsFilterModalOpen(false)}
        onSearch={handleSearchWithFilters}
      />
      <SuggestionModal
        isOpen={isSuggestionModalOpen}
        onClose={() => setIsSuggestionModalOpen(false)}
        onSearch={handleSuggestionSearch}
      />
      {viewingImage && (
        <ImageViewerModal 
          src={viewingImage} 
          onClose={() => setViewingImage(null)} 
        />
      )}
      {isVoiceAssistantOpen && (
        <CameraVoiceAssistant onClose={() => setIsVoiceAssistantOpen(false)} />
      )}
      <div className="flex flex-col h-[100dvh] font-sans overflow-hidden">
        <header className="p-3 md:p-4 flex items-center gap-3 sticky top-0 z-10 glassmorphism shrink-0">
          <div className="p-2 bg-gradient-to-br from-green-400 to-green-600 rounded-full shadow-lg">
            <SmileIcon className="w-6 h-6 md:w-8 md:h-8 text-white" />
          </div>
          <div className="flex-1">
            <h1 className="text-xl md:text-2xl font-extrabold text-slate-800 tracking-tight">Medimart AI</h1>
            <p className="text-xs md:text-sm text-green-600 font-semibold flex items-center">
              <span className="w-2 h-2 bg-green-500 rounded-full mr-1.5 animate-pulse"></span>
              Online
            </p>
          </div>
          <button 
            onClick={() => setIsVoiceAssistantOpen(true)}
            className="p-3 bg-white shadow-md rounded-full text-green-600 hover:text-green-700 active:scale-95 transition-all neumorphic-convex border border-green-100"
            title="Voice Scan Assistant"
          >
            <CameraIcon className="w-6 h-6" />
          </button>
        </header>

        <main className="flex-1 overflow-y-auto p-3 md:p-6 space-y-6 md:space-y-8 pb-4">
          {messages.map((msg, index) => (
            <ChatMessage 
              key={msg.id || index} 
              message={msg} 
              isLoading={msg.isLoading}
              onTranslate={handleTranslate} 
              onImageView={handleImageView}
            />
          ))}
          <div ref={messagesEndRef} />
        </main>

        <footer className="p-2 sticky bottom-0 z-20 shrink-0 bg-white/30 backdrop-blur-md">
          <div className="max-w-4xl mx-auto space-y-2">
              <div className="grid grid-cols-2 gap-2 px-1">
                  <button 
                      onClick={() => setIsFilterModalOpen(true)} 
                      disabled={isLoading}
                      className="flex items-center justify-center px-3 py-3 text-sm font-bold text-slate-700 neumorphic-convex disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                      <MapPinIcon className="w-4 h-4 md:w-5 md:h-5 mr-1.5 text-green-500" />
                      Find Doctor
                  </button>
                  <button 
                      onClick={() => setIsSuggestionModalOpen(true)}
                      disabled={isLoading}
                      className="flex items-center justify-center px-3 py-3 text-sm font-bold text-slate-700 neumorphic-convex disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                      <LightbulbIcon className="w-4 h-4 md:w-5 md:h-5 mr-1.5 text-yellow-500" />
                      Compare
                  </button>
              </div>
              <ChatInput onSend={handleSend} isLoading={isLoading} />
              <p className="text-[10px] md:text-xs text-center text-red-700 px-4 py-1.5 bg-red-100 rounded-lg shadow-inner mx-1">
                <strong>Disclaimer:</strong> Medimart AI is not a substitute for professional medical advice.
              </p>
          </div>
        </footer>
      </div>
    </>
  );
};

export default App;

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, Blob } from '@google/genai';
import { CloseIcon } from './icons/CloseIcon';
import { CameraIcon } from './icons/CameraIcon';
import { MicroIcon } from './icons/MicroIcon';

interface CameraVoiceAssistantProps {
  onClose: () => void;
}

const FRAME_RATE = 1; // 1 frame per second for vision
const JPEG_QUALITY = 0.5;

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

function encode(bytes: Uint8Array) {
  let binary = '';
  const len = bytes.byteLength;
  for (let i = 0; i < len; i++) {
    binary += String.fromCharCode(bytes[i]);
  }
  return btoa(binary);
}

function createBlob(data: Float32Array): Blob {
  const l = data.length;
  const int16 = new Int16Array(l);
  for (let i = 0; i < l; i++) {
    int16[i] = data[i] * 32768;
  }
  return {
    data: encode(new Uint8Array(int16.buffer)),
    mimeType: 'audio/pcm;rate=16000',
  };
}

export const CameraVoiceAssistant: React.FC<CameraVoiceAssistantProps> = ({ onClose }) => {
  const [status, setStatus] = useState<'connecting' | 'active' | 'error' | 'closing'>('connecting');
  const [errorMessage, setErrorMessage] = useState('');
  const [isSpeaking, setIsSpeaking] = useState(false);

  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const sessionRef = useRef<any>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const frameIntervalRef = useRef<number | null>(null);

  const audioContextInRef = useRef<AudioContext | null>(null);
  const audioContextOutRef = useRef<AudioContext | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  useEffect(() => {
    const initAssistant = async () => {
      try {
        const stream = await navigator.mediaDevices.getUserMedia({ 
            audio: true, 
            video: { facingMode: 'environment' } 
        });
        streamRef.current = stream;
        if (videoRef.current) videoRef.current.srcObject = stream;

        const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

        audioContextInRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 16000 });
        audioContextOutRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });

        const sessionPromise = ai.live.connect({
          model: 'gemini-2.5-flash-native-audio-preview-09-2025',
          callbacks: {
            onopen: () => {
              setStatus('active');
              // Start audio stream
              const source = audioContextInRef.current!.createMediaStreamSource(stream);
              const scriptProcessor = audioContextInRef.current!.createScriptProcessor(4096, 1, 1);
              scriptProcessor.onaudioprocess = (e) => {
                const inputData = e.inputBuffer.getChannelData(0);
                const pcmBlob = createBlob(inputData);
                sessionPromise.then((session) => {
                  session.sendRealtimeInput({ media: pcmBlob });
                });
              };
              source.connect(scriptProcessor);
              scriptProcessor.connect(audioContextInRef.current!.destination);

              // Start video/frame stream
              frameIntervalRef.current = window.setInterval(() => {
                if (canvasRef.current && videoRef.current) {
                  const ctx = canvasRef.current.getContext('2d');
                  canvasRef.current.width = videoRef.current.videoWidth;
                  canvasRef.current.height = videoRef.current.videoHeight;
                  ctx?.drawImage(videoRef.current, 0, 0);
                  canvasRef.current.toBlob(async (blob) => {
                    if (blob) {
                      const reader = new FileReader();
                      reader.readAsDataURL(blob);
                      reader.onloadend = () => {
                        const base64Data = (reader.result as string).split(',')[1];
                        sessionPromise.then(s => s.sendRealtimeInput({ media: { data: base64Data, mimeType: 'image/jpeg' } }));
                      };
                    }
                  }, 'image/jpeg', JPEG_QUALITY);
                }
              }, 1000 / FRAME_RATE);
            },
            onmessage: async (message: LiveServerMessage) => {
              const audioBase64 = message.serverContent?.modelTurn?.parts[0]?.inlineData?.data;
              if (audioBase64) {
                setIsSpeaking(true);
                const ctx = audioContextOutRef.current!;
                nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
                const buffer = await decodeAudioData(decode(audioBase64), ctx, 24000, 1);
                const source = ctx.createBufferSource();
                source.buffer = buffer;
                source.connect(ctx.destination);
                source.addEventListener('ended', () => {
                  sourcesRef.current.delete(source);
                  if (sourcesRef.current.size === 0) setIsSpeaking(false);
                });
                source.start(nextStartTimeRef.current);
                nextStartTimeRef.current += buffer.duration;
                sourcesRef.current.add(source);
              }

              if (message.serverContent?.interrupted) {
                sourcesRef.current.forEach(s => s.stop());
                sourcesRef.current.clear();
                nextStartTimeRef.current = 0;
                setIsSpeaking(false);
              }
            },
            onerror: (e) => {
              console.error('Live API Error:', e);
              setStatus('error');
              setErrorMessage('Failed to connect to Medimart AI Voice Engine.');
            },
            onclose: () => {
              setStatus('closing');
              onClose();
            },
          },
          config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: {
              voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Zephyr' } },
            },
            systemInstruction: `You are Medimart AI Camera Voice Assistant, a multilingual healthcare support assistant for Medimart.
Your role:
- Analyze medical documents (lab reports, prescriptions, scan summaries) captured through the device camera in real-time.
- Explain information in a simple, calm, and reassuring manner.
- Speak ONLY in the user's preferred language: Assamese, Hindi, or English.
- Provide preliminary, educational, and supportive information only.
- MANDATORY: Always include a medical disclaimer.
- STRICTLY: Do NOT diagnose diseases or prescribe medicines.
- Use phrases like "this may indicate" or "often associated with".
- If a report looks critical, advise immediate medical attention politely.
- Tone: Caring, respectful, and non-technical. Speak like a trusted health guide.`,
          },
        });
        sessionRef.current = await sessionPromise;
      } catch (err: any) {
        console.error('Initialization error:', err);
        setStatus('error');
        setErrorMessage(err.message || 'Camera or Microphone access denied.');
      }
    };

    initAssistant();

    return () => {
      if (frameIntervalRef.current) clearInterval(frameIntervalRef.current);
      if (streamRef.current) streamRef.current.getTracks().forEach(t => t.stop());
      if (sessionRef.current) sessionRef.current.close();
      audioContextInRef.current?.close();
      audioContextOutRef.current?.close();
    };
  }, []);

  return (
    <div className="fixed inset-0 z-[100] bg-slate-900 flex flex-col items-center justify-between p-6">
      <div className="w-full flex justify-between items-center text-white">
        <div className="flex items-center gap-3">
          <div className={`w-3 h-3 rounded-full ${status === 'active' ? 'bg-green-500 animate-pulse' : 'bg-yellow-500'}`}></div>
          <h2 className="text-lg font-bold">Voice Scan Assistant</h2>
        </div>
        <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full transition-colors">
          <CloseIcon className="w-6 h-6" />
        </button>
      </div>

      <div className="relative w-full max-w-lg aspect-[3/4] rounded-3xl overflow-hidden bg-black shadow-2xl border-4 border-slate-800">
        <video ref={videoRef} autoPlay playsInline muted className="w-full h-full object-cover" />
        <canvas ref={canvasRef} className="hidden" />

        {/* Visual Overlay */}
        <div className="absolute inset-0 pointer-events-none flex flex-col justify-center items-center">
            {status === 'connecting' && (
                <div className="bg-black/60 backdrop-blur-md px-6 py-4 rounded-2xl flex flex-col items-center">
                    <div className="w-10 h-10 border-4 border-green-500 border-t-transparent rounded-full animate-spin mb-3"></div>
                    <p className="text-white font-semibold">Initializing AI Engine...</p>
                </div>
            )}
            {status === 'error' && (
                <div className="bg-red-500/80 backdrop-blur-md px-6 py-4 rounded-2xl text-center mx-4">
                    <p className="text-white font-bold mb-2">Error Occurred</p>
                    <p className="text-white text-sm">{errorMessage}</p>
                    <button onClick={onClose} className="mt-4 px-4 py-2 bg-white text-red-600 rounded-lg font-bold">Go Back</button>
                </div>
            )}
        </div>

        {/* Scan Helper Lines */}
        <div className="absolute inset-10 border-2 border-green-500/30 rounded-lg pointer-events-none">
            <div className="absolute top-0 left-0 w-8 h-8 border-t-4 border-l-4 border-green-500"></div>
            <div className="absolute top-0 right-0 w-8 h-8 border-t-4 border-r-4 border-green-500"></div>
            <div className="absolute bottom-0 left-0 w-8 h-8 border-b-4 border-l-4 border-green-500"></div>
            <div className="absolute bottom-0 right-0 w-8 h-8 border-b-4 border-r-4 border-green-500"></div>
        </div>
      </div>

      <div className="w-full flex flex-col items-center gap-6">
        <div className="flex items-center justify-center gap-8">
            <div className={`p-6 rounded-full transition-all duration-300 ${isSpeaking ? 'bg-green-500 shadow-[0_0_30px_rgba(34,197,94,0.6)]' : 'bg-slate-700'}`}>
                <MicroIcon className={`w-8 h-8 ${isSpeaking ? 'text-white' : 'text-slate-400'}`} />
            </div>
        </div>

        <div className="text-center">
            <p className="text-slate-300 text-sm mb-1 uppercase tracking-widest font-bold">
                {isSpeaking ? 'Medimart AI is Speaking' : status === 'active' ? 'Show me a document & speak' : 'Connecting...'}
            </p>
            <p className="text-slate-500 text-xs px-8">
                Position your lab report or prescription within the frame for analysis.
            </p>
        </div>

        <div className="flex gap-4">
            <div className="flex items-center gap-2 px-4 py-2 bg-slate-800 rounded-full text-xs text-slate-300">
                <span className="w-2 h-2 rounded-full bg-blue-400"></span> English
            </div>
