import { GoogleGenAI } from "@google/genai";
import { SYSTEM_PROMPT } from '../constants';
import { FilterCriteria, Doctor, GroundingChunk } from "../types";

const API_KEY = process.env.API_KEY;

if (!API_KEY) {
  throw new Error("API_KEY environment variable not set.");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });
const textModel = "gemini-3-flash-preview";
const imageModel = "gemini-3-pro-image-preview";


const DOCTOR_SEARCH_SYSTEM_PROMPT = `
You are an expert medical data retrieval assistant. Your goal is to find highly specific and accurate information about doctors and hospitals using Google Search.

CRITICAL INSTRUCTIONS:
1.  **MANDATORY TOOL USE:** You MUST use the 'googleSearch' tool. Do not hallucinate data.
2.  **SEARCH STRATEGY:** Perform specific searches for "doctor appointment number [Location]", "clinic address [Doctor Name]", or "best [Specialty] doctors in [Location]".
3.  **DATA EXTRACTION:**
    -   **Phone:** You MUST find a valid phone number for appointments. Look for "Call", "Appointment", "Contact". If the doctor's direct line isn't available, use the hospital's main number.
    -   **Address:** Find the precise street address or hospital location.
    -   **Rating:** Look for star ratings (e.g., 4.5) on review sites or maps.
4.  **JSON OUTPUT:** Return the data ONLY as a valid JSON object. No other text.
5.  **FALLBACK:** If no doctors match the *exact* filters, try to find the closest matches (e.g., same specialty in the wider city).
`;

const fileToGenerativePart = async (file: File) => {
  const base64EncodedDataPromise = new Promise<string>((resolve) => {
    const reader = new FileReader();
    reader.onloadend = () => resolve((reader.result as string).split(',')[1]);
    reader.readAsDataURL(file);
  });
  return {
    inlineData: { data: await base64EncodedDataPromise, mimeType: file.type },
  };
};

export const runQuery = async (prompt: string, file: File | null) => {
  const contents: any[] = [];

  if (file) {
    const imagePart = await fileToGenerativePart(file);
    contents.push(imagePart);
  }

  contents.push({ text: prompt });

  const result = await ai.models.generateContentStream({
    model: textModel,
    contents: { parts: contents },
    config: {
        systemInstruction: SYSTEM_PROMPT,
    }
  });

  return result;
};

export const findDoctors = async (latitude: number | null, longitude: number | null, filters: FilterCriteria): Promise<{ doctors: Doctor[] | null, groundingChunks: GroundingChunk[] | undefined }> => {
  let locationQuery = filters.location;
  if (!locationQuery && latitude && longitude) {
    locationQuery = `near coordinates ${latitude}, ${longitude}`;
  } else if (!locationQuery) {
    locationQuery = "near me";
  }

  const queryParts = [];
  if (filters.doctorName) queryParts.push(`Dr. ${filters.doctorName}`);
  if (filters.specialty) queryParts.push(`${filters.specialty} doctors`);
  else if (!filters.doctorName) queryParts.push("doctors"); 

  if (filters.hospitalName) queryParts.push(`at ${filters.hospitalName}`);

  queryParts.push(`in ${locationQuery}`);

  const searchQuery = queryParts.join(' ');

  const prompt = `
Perform a deep search to find doctors matching this query: "${searchQuery}".

Specific Data Required for each doctor:
1.  **Name**: Full name.
2.  **Specialty**: e.g., Cardiologist.
3.  **Hospital**: Associated hospital or clinic name.
4.  **Phone**: A valid appointment booking phone number.
5.  **Address**: Full street address.
6.  **Rating**: Numeric rating.

Return a single JSON object with this EXACT structure:
{
  "doctors": [
    {
      "name": "string",
      "specialty": "string",
      "hospitalName": "string",
      "address": "string",
      "phone": "string",
      "rating": number
    }
  ]
}
`;

  try {
    const response = await ai.models.generateContent({
      model: textModel,
      contents: prompt,
      config: {
        systemInstruction: DOCTOR_SEARCH_SYSTEM_PROMPT,
        tools: [{googleSearch: {}}],
      }
    });

    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks as GroundingChunk[] | undefined;
    const responseText = response.text;

    if (!responseText) return { doctors: null, groundingChunks };

    const jsonMatch = responseText.match(/\{[\s\S]*\}/);
    if (!jsonMatch) return { doctors: null, groundingChunks };

    const jsonString = jsonMatch[0];
    const parsedJson = JSON.parse(jsonString);

    if (parsedJson && Array.isArray(parsedJson.doctors)) {
      const validDoctors: Doctor[] = parsedJson.doctors
        .map((doc: any) => ({
          name: doc.name || "Unknown Doctor",
          specialty: doc.specialty || "General",
          address: doc.address || "Address not available",
          rating: parseFloat(doc.rating) || 0, 
          hospitalName: doc.hospitalName || "Private Clinic",
          phone: doc.phone || "Number not available online",
        }))
        .filter((doc: Doctor) => doc.name && doc.name !== "Unknown Doctor");

      return { doctors: validDoctors, groundingChunks };
    }
    return { doctors: null, groundingChunks };
  } catch (e) {
    return { doctors: null, groundingChunks: undefined };
  }
};

export const translateToAssamese = async (text: string): Promise<string> => {
    try {
        const prompt = `Translate the following English text into Assamese. Provide only the Assamese translation.\n\nEnglish: "${text}"`;
        const response = await ai.models.generateContent({ model: textModel, contents: prompt });
        return response.text?.trim() || "Translation not available.";
    } catch (error) {
        return "Sorry, I was unable to translate the text.";
    }
};

export const generateComparisonImage = async (query: string): Promise<{ image: string | null, error: string | null }> => {
  const parts = query.split(/vs|versus/i).map(p => p.trim());
  if (parts.length < 2) return { image: null, error: "Please provide two product names to compare, separated by 'vs'." };
  const [product1, product2] = parts;

  const prompt = `
Generate an ultra-high-resolution (4K), professional medical comparison infographic.
Topic: "${product1}" vs "${product2}".

Design Specs:
1. LAYOUT: Clean vertical split. High contrast. 
2. TYPOGRAPHY: Large, bold, legible technical labels. No blurry text.
3. CONTENT FOR BOTH SIDES:
   - 3D Realistic visualization of the medicine/item.
   - Key Facts Table: Composition, Main Use, Typical Dose, Side Effects, and Price Level.
   - A "Pro Tip" glassmorphism box at the bottom for each.
4. COMPARISON HIGHLIGHTS: Use glowing green checkmarks (✅) for advantages and red icons for warnings.
5. STYLE: Modern Hospital Tech UI. White background with soft clinical green accents (#00A878). 
6. LEGIBILITY: All text MUST be large enough to be read when zoomed in. Focus on sharp borders and high contrast.
7. BRANDING: "Medical Analysis by Medimart AI" in elegant small caps at the very bottom center.

The image should look like a high-end medical tablet interface.
`;

  try {
    const ai = new GoogleGenAI({ apiKey: API_KEY });
    const response = await ai.models.generateContent({
      model: imageModel,
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: {
          imageSize: "1K", // High resolution base
          aspectRatio: "3:4"
        }
      }
    });

    for (const part of response.candidates?.[0].content.parts ?? []) {
      if (part.inlineData) return { image: part.inlineData.data, error: null };
    }
    return { image: null, error: "Image generation failed." };
  } catch (error) {
    return { image: null, error: "Service error." };
  }
};

import React, { useEffect, useState, useRef } from 'react';
import { CloseIcon } from './icons/CloseIcon';

interface ImageViewerModalProps {
  src: string;
  onClose: () => void;
}

export const ImageViewerModal: React.FC<ImageViewerModalProps> = ({ src, onClose }) => {
  const [isVisible, setIsVisible] = useState(false);
  const [scale, setScale] = useState(1);
  const [position, setPosition] = useState({ x: 0, y: 0 });
  const [isDragging, setIsDragging] = useState(false);
  const dragStart = useRef({ x: 0, y: 0 });
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setIsVisible(true);
    const handleEsc = (event: KeyboardEvent) => {
      if (event.key === 'Escape') handleClose();
    };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, []);

  const handleClose = () => {
    setIsVisible(false);
    setTimeout(onClose, 300); 
  };

  const handleZoomIn = () => setScale(prev => Math.min(prev + 0.5, 4));
  const handleZoomOut = () => {
    setScale(prev => {
      const newScale = Math.max(prev - 0.5, 1);
      if (newScale === 1) setPosition({ x: 0, y: 0 });
      return newScale;
    });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
    if (scale > 1) {
      setIsDragging(true);
      dragStart.current = { x: e.clientX - position.x, y: e.clientY - position.y };
    }
  };

  const handleMouseMove = (e: React.MouseEvent) => {
    if (isDragging && scale > 1) {
      setPosition({
        x: e.clientX - dragStart.current.x,
        y: e.clientY - dragStart.current.y
      });
    }
  };

  const handleMouseUp = () => setIsDragging(false);

  return (
    <div
      className={`fixed inset-0 bg-black/90 z-[100] flex flex-col items-center justify-center transition-opacity duration-300 ${isVisible ? 'opacity-100' : 'opacity-0'}`}
      onMouseUp={handleMouseUp}
      onMouseLeave={handleMouseUp}
    >
      {/* Header Controls */}
      <div className="absolute top-0 inset-x-0 p-4 flex justify-between items-center z-[110] bg-gradient-to-b from-black/50 to-transparent">
        <div className="flex gap-2">
          <button 
            onClick={handleZoomIn}
            className="p-3 bg-white/10 hover:bg-white/20 text-white rounded-xl backdrop-blur-md border border-white/20 transition-all font-bold"
          >
            Zoom +
          </button>
          <button 
            onClick={handleZoomOut}
            className="p-3 bg-white/10 hover:bg-white/20 text-white rounded-xl backdrop-blur-md border border-white/20 transition-all font-bold"
          >
            Zoom -
          </button>
          {scale > 1 && (
             <button 
                onClick={() => { setScale(1); setPosition({ x: 0, y: 0 }); }}
                className="p-3 bg-white/10 hover:bg-white/20 text-white rounded-xl backdrop-blur-md border border-white/20 transition-all font-bold"
              >
                Reset
              </button>
          )}
        </div>
        <button
          onClick={handleClose}
          className="p-3 bg-white text-slate-900 rounded-full shadow-lg hover:bg-slate-200 transition-all active:scale-95"
        >
          <CloseIcon className="w-6 h-6" />
        </button>
      </div>

      {/* Image Container */}
      <div 
        ref={containerRef}
        className="relative w-full h-full flex items-center justify-center overflow-hidden cursor-grab active:cursor-grabbing"
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
      >
        <div 
          className="transition-transform duration-200 ease-out flex items-center justify-center"
          style={{ 
            transform: `translate(${position.x}px, ${position.y}px) scale(${scale})`,
          }}
        >
          <img
            src={`data:image/png;base64,${src}`}
            alt="Full screen medical analysis"
            className="max-w-[95vw] max-h-[85vh] object-contain rounded-lg shadow-2xl pointer-events-none select-none"
            onDragStart={(e) => e.preventDefault()}
          />
        </div>
