      {/* Footer Info */}
      <div className="absolute bottom-6 px-6 py-3 bg-white/10 backdrop-blur-md border border-white/10 rounded-2xl text-white/80 text-sm pointer-events-none">
        {scale > 1 ? 'Drag to pan around details' : 'Pinch or click Zoom to inspect text'}
      </div>
    </div>
  );
};

import React from 'react';
import { Message } from '../types';
import { UserIcon } from './icons/UserIcon';
import { marked } from 'marked';
import { DoctorCard } from './DoctorCard';
import { TranslateIcon } from './icons/TranslateIcon';
import { WebIcon } from './icons/WebIcon';
import { MascotIcon } from './icons/MascotIcon';
import { SearchIcon } from './icons/SearchIcon';

interface ChatMessageProps {
  message: Message;
  isLoading?: boolean;
  onTranslate?: (messageId: string, text: string) => void;
  onImageView?: (imageSrc: string) => void;
}

const renderer = new marked.Renderer();
const originalLinkRenderer = renderer.link;
renderer.link = (href, title, text) => {
  const html = originalLinkRenderer.call(renderer, href, title, text);
  return html.replace(/^<a /, '<a target="_blank" rel="noopener noreferrer" class="font-bold" ');
};
marked.setOptions({
  renderer,
  gfm: true,
  breaks: true,
  sanitize: true,
});

export const ChatMessage: React.FC<ChatMessageProps> = ({ message, isLoading, onTranslate, onImageView }) => {
  const isModel = message.role === 'model';

  const createMarkup = (text: string) => {
    const rawMarkup = marked.parse(text) as string;
    return { __html: rawMarkup };
  };

  const filePreview = message.file ? (
    <div className="mt-2 p-2 bg-black/10 rounded-lg">
      <img
        src={URL.createObjectURL(message.file)}
        alt="Uploaded content"
        className="max-w-xs max-h-64 rounded-lg"
        onLoad={(e) => URL.revokeObjectURL((e.target as HTMLImageElement).src)}
      />
    </div>
  ) : null;

  const canTranslate = isModel && onTranslate && message.parts[0]?.text && !message.comparisonImage;

  return (
    <div className={`flex items-end gap-3 ${isModel ? 'justify-start' : 'justify-end'}`}>
      {isModel && (
        <div className="flex-shrink-0 w-10 h-10 rounded-full neumorphic-convex flex items-center justify-center p-1">
          <MascotIcon className="w-8 h-8" />
        </div>
      )}

      <div className={`max-w-2xl w-auto`}>
        <div className={`${isModel ? 'chat-bubble-model' : 'chat-bubble-user'}`}>
          {isLoading ? (
              <div className="px-4 py-3 flex items-center gap-2">
                  <span className="w-2 h-2 bg-current opacity-50 rounded-full animate-pulse delay-0"></span>
                  <span className="w-2 h-2 bg-current opacity-50 rounded-full animate-pulse delay-150"></span>
                  <span className="w-2 h-2 bg-current opacity-50 rounded-full animate-pulse delay-300"></span>
              </div>
          ) : (
            <>
              {message.parts[0].text && (
                 <div 
                    className="prose-chat prose-sm max-w-none prose-p:my-2 prose-headings:my-3 prose-ul:my-2 prose-ol:my-2"
                    dangerouslySetInnerHTML={createMarkup(message.parts[0].text)} 
                 />
              )}
              {message.doctors && message.doctors.length > 0 && (
                <div className="space-y-3 pt-2">
                  {message.doctors.map((doctor, index) => (
                    <DoctorCard key={index} doctor={doctor} />
                  ))}
                </div>
              )}
               {message.comparisonImage && (
                <div className="mt-3 relative group">
                  <div className="absolute top-3 right-3 z-10 p-2 bg-black/40 backdrop-blur-md rounded-lg text-white text-[10px] font-bold flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none border border-white/20">
                    <SearchIcon className="w-3 h-3" />
                    TAP TO ZOOM
                  </div>
                  <div className="p-1 bg-white/20 rounded-xl overflow-hidden shadow-inner">
                    <img
                      src={`data:image/png;base64,${message.comparisonImage}`}
                      alt="Product comparison infographic"
                      className="max-w-full rounded-lg shadow-2xl cursor-pointer hover:scale-[1.02] transition-transform duration-300"
                      onClick={() => onImageView && onImageView(message.comparisonImage!)}
                    />
                  </div>
                  <p className="text-[10px] italic mt-2 opacity-70 text-center">Tap image for deep analysis zoom</p>
                </div>
              )}
              {filePreview}

              {message.groundingChunks && message.groundingChunks.length > 0 && (
                  <div className="pt-3 mt-3 border-t border-white/20">
                      <h4 className="flex items-center text-xs font-bold opacity-80 mb-2">
                          <WebIcon className="w-4 h-4 mr-1.5" />
                          Sources from the web
                      </h4>
                      <ul className="space-y-1 list-none p-0 m-0">
                          {message.groundingChunks.map((chunk, index) => (
                              chunk.web && (
                                  <li key={index} className="text-xs">
                                      <a 
                                          href={chunk.web.uri} 
                                          target="_blank" 
                                          rel="noopener noreferrer"
                                          className="hover:underline truncate block"
                                          title={chunk.web.title}
                                      >
                                         {index + 1}. {chunk.web.title || chunk.web.uri}
                                      </a>
                                  </li>
                              )
                          ))}
                      </ul>
                  </div>
              )}

              {canTranslate && !message.translatedText && (
                  <div className="pt-2 mt-2 border-t border-white/20">
                      <button 
                          onClick={() => onTranslate(message.id, message.parts[0].text)}
                          disabled={message.isTranslating}
                          className="flex items-center text-xs font-semibold opacity-80 hover:opacity-100 disabled:opacity-50 disabled:cursor-wait transition-opacity"
                      >
                           {message.isTranslating ? (
                                <>
                                    <div className="w-4 h-4 border-2 border-current border-t-transparent rounded-full animate-spin mr-1.5"></div>
                                    Translating...
                                </>
                           ) : (
                                <>
                                    <TranslateIcon className="w-4 h-4 mr-1.5" />
                                    Translate to Assamese
                                </>
                           )}
                      </button>
                  </div>
              )}
              {message.translatedText && (
                  <div className="pt-3 mt-3 border-t border-white/20">
                      <h4 className="text-xs font-bold opacity-80 mb-1">Assamese Translation</h4>
                      <p lang="as" className="text-sm font-assamese">{message.translatedText}</p>
                  </div>
              )}
            </>
          )}
        </div>
        <p className={`text-xs mt-2 px-2 ${isModel ? 'text-left' : 'text-right'} text-slate-500`}>
          {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
        </p>
      </div>

      {!isModel && (
        <div className="flex-shrink-0 w-10 h-10 rounded-full bg-slate-700 flex items-center justify-center text-white shadow-inner">
          <UserIcon className="w-6 h-6" />
        </div>
      )}
    </div>
  );
};

