  gfm: true,
  breaks: true,
  sanitize: true,
});

export const ChatMessage: React.FC<ChatMessageProps> = ({ message, isLoading, onTranslate, onImageView, onFixKey }) => {
  const isModel = message.role === 'model';

  const createMarkup = (text: string) => {
    const rawMarkup = marked.parse(text) as string;
    return { __html: rawMarkup };
  };

  const filePreview = message.file ? (
    <div className="mt-2 p-2 bg-black/10 rounded-lg">
      <img
        src={URL.createObjectURL(message.file)}
        alt="Uploaded content"
        className="max-w-xs max-h-64 rounded-lg"
        onLoad={(e) => URL.revokeObjectURL((e.target as HTMLImageElement).src)}
      />
    </div>
  ) : null;

  return (
    <div className={`flex items-end gap-3 ${isModel ? 'justify-start' : 'justify-end'}`}>
      {isModel && (
        <div className="flex-shrink-0 w-10 h-10 rounded-full neumorphic-convex flex items-center justify-center p-1">
          <MascotIcon className="w-8 h-8" />
        </div>
      )}

      <div className={`max-w-2xl w-auto`}>
        <div className={`${isModel ? 'chat-bubble-model' : 'chat-bubble-user'} ${message.isPermissionError ? 'border-2 border-red-400 !bg-red-50 !text-red-900' : ''}`}>
          {isLoading ? (
              <div className="px-4 py-3 flex items-center gap-2">
                  <span className="w-2 h-2 bg-current opacity-50 rounded-full animate-pulse"></span>
                  <span className="w-2 h-2 bg-current opacity-50 rounded-full animate-pulse delay-150"></span>
                  <span className="w-2 h-2 bg-current opacity-50 rounded-full animate-pulse delay-300"></span>
              </div>
          ) : (
            <>
              {message.parts[0].text && (
                 <div 
                    className="prose-chat prose-sm max-w-none"
                    dangerouslySetInnerHTML={createMarkup(message.parts[0].text)} 
                 />
              )}

              {message.isPermissionError && onFixKey && (
                <button 
                  onClick={onFixKey}
                  className="mt-4 flex items-center gap-2 px-4 py-2 bg-white text-red-600 rounded-xl font-bold border border-red-200 shadow-sm active:scale-95 transition-all"
                >
                  <KeyIcon className="w-4 h-4" />
                  Update API Key
                </button>
              )}

              {message.doctors && message.doctors.length > 0 && (
                <div className="space-y-3 pt-2">
                  {message.doctors.map((doctor, index) => (
                    <DoctorCard key={index} doctor={doctor} />
                  ))}
                </div>
              )}

              {message.comparisonImage && (
                <div className="mt-3 relative group">
                  <div className="absolute top-3 right-3 z-10 p-2 bg-black/40 backdrop-blur-md rounded-lg text-white text-[10px] font-bold flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
                    <SearchIcon className="w-3 h-3" />
                    TAP TO ZOOM
                  </div>
                  <img
                    src={`data:image/png;base64,${message.comparisonImage}`}
                    alt="Infographic"
                    className="max-w-full rounded-lg shadow-2xl cursor-pointer hover:scale-[1.01] transition-transform"
                    onClick={() => onImageView && onImageView(message.comparisonImage!)}
                  />
                </div>
              )}

              {filePreview}

              {message.groundingChunks && message.groundingChunks.length > 0 && (
                  <div className="pt-3 mt-3 border-t border-white/20">
                      <h4 className="flex items-center text-xs font-bold opacity-80 mb-2">
                          <WebIcon className="w-4 h-4 mr-1.5" /> Sources
                      </h4>
                      <ul className="space-y-1 list-none p-0 m-0">
                          {message.groundingChunks.map((chunk, index) => (
                              chunk.web && (
                                  <li key={index} className="text-xs">
                                      <a href={chunk.web.uri} target="_blank" rel="noopener" className="hover:underline truncate block">
                                         {index + 1}. {chunk.web.title || "Reference"}
                                      </a>
                                  </li>
                              )
                          ))}
                      </ul>
                  </div>
              )}

              {isModel && !message.translatedText && message.parts[0]?.text && !message.comparisonImage && !message.isPermissionError && (
                  <button 
                      onClick={() => onTranslate!(message.id, message.parts[0].text)}
                      disabled={message.isTranslating}
                      className="mt-3 flex items-center text-xs font-semibold opacity-80 hover:opacity-100 disabled:opacity-50"
                  >
                       {message.isTranslating ? 'Translating...' : <><TranslateIcon className="w-4 h-4 mr-1.5" /> Translate to Assamese</>}
                  </button>
              )}
              {message.translatedText && (
                  <div className="pt-3 mt-3 border-t border-white/20 font-assamese text-sm">
                      {message.translatedText}
                  </div>
              )}
            </>
          )}
        </div>
        <p className={`text-[10px] mt-1 px-2 ${isModel ? 'text-left' : 'text-right'} text-slate-400`}>
          {message.timestamp.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
        </p>
      </div>

      {!isModel && (
        <div className="flex-shrink-0 w-8 h-8 rounded-full bg-slate-700 flex items-center justify-center text-white">
          <UserIcon className="w-5 h-5" />
        </div>
      )}
    </div>
  );
};

export type Role = 'user' | 'model';

export interface MessagePart {
    text: string;
}

export interface Doctor {
    name: string;
    specialty: string;
    address: string;
    rating: number;
    hospitalName?: string;
    phone?: string;
}

export interface WebSource {
    uri: string;
    title: string;
}

export interface GroundingChunk {
    web: WebSource;
}

export interface Message {
  id: string;
  role: Role;
  parts: MessagePart[];
  timestamp: Date;
  file?: File;
  doctors?: Doctor[];
  isLoading?: boolean;
  translatedText?: string;
  isTranslating?: boolean;
  groundingChunks?: GroundingChunk[];
  comparisonImage?: string;
  isPermissionError?: boolean;
}

export interface FilterCriteria {
  specialty: string;
  availableNow: boolean;
  location: string;
  doctorName: string;
  hospitalName: string;
}

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { Message, Doctor, FilterCriteria } from './types';
import { ChatInput } from './components/ChatInput';
import { ChatMessage } from './components/ChatMessage';
import { runQuery, findDoctors as findDoctorsService, translateToAssamese, generateComparisonImage } from './services/geminiService';
import { MapPinIcon } from './components/icons/MapPinIcon';
import { FilterModal } from './components/FilterModal';
import { SmileIcon } from './components/icons/SmileIcon';
import { SuggestionModal } from './components/SuggestionModal';
import { LightbulbIcon } from './components/icons/LightbulbIcon';
import { ImageViewerModal } from './components/ImageViewerModal';
import { CameraVoiceAssistant } from './components/CameraVoiceAssistant';
import { CameraIcon } from './components/icons/CameraIcon';
import { KeyIcon } from './components/icons/KeyIcon';
import { MascotIcon } from './components/icons/MascotIcon';

declare global {
  interface AIStudio {
    hasSelectedApiKey: () => Promise<boolean>;
    openSelectKey: () => Promise<void>;
  }
  interface Window {
    aistudio?: AIStudio;
  }
}

const generateUniqueId = () => `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;

const App: React.FC = () => {
  const [hasKey, setHasKey] = useState<boolean | null>(null);
  const [messages, setMessages] = useState<Message[]>([
    {
      id: generateUniqueId(),
      role: 'model',
      parts: [{ text: "Hello! I'm Medimart AI, your friendly medical assistant. How can I help you today? You can ask me about medications, upload a prescription, or ask me to find a doctor nearby." }],
      timestamp: new Date(),
    },
  ]);
  const [isLoading, setIsLoading] = useState(false);
  const [isFilterModalOpen, setIsFilterModalOpen] = useState(false);
  const [isSuggestionModalOpen, setIsSuggestionModalOpen] = useState(false);
  const [isVoiceAssistantOpen, setIsVoiceAssistantOpen] = useState(false);
  const [viewingImage, setViewingImage] = useState<string | null>(null);

  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const checkKey = async () => {
      if (window.aistudio) {
        const selected = await window.aistudio.hasSelectedApiKey();
        setHasKey(selected);
      } else {
        setHasKey(true); // Fallback for environments without the selector
      }
    };
    checkKey();
  }, []);

  const handleOpenKeySelector = async () => {
    if (window.aistudio) {
      await window.aistudio.openSelectKey();
      setHasKey(true); // Proceed assuming success per guidelines
    }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = useCallback(async (text: string, file: File | null) => {
    if (!text && !file) return;

    setIsLoading(true);
    const userMessage: Message = {
      id: generateUniqueId(),
      role: 'user',
      parts: [{ text }],
      timestamp: new Date(),
    };
    if (file) userMessage.file = file;

    setMessages(prev => [...prev, userMessage]);

    const placeholderId = generateUniqueId();
    setMessages(prev => [...prev, { id: placeholderId, role: 'model', parts: [{ text: '' }], timestamp: new Date(), isLoading: true }]);

    try {
      const stream = await runQuery(text, file);
      let fullResponse = '';
      for await (const chunk of stream) {
        fullResponse += chunk.text;
        setMessages(prev => prev.map(msg => 
            msg.id === placeholderId ? { ...msg, parts: [{ text: fullResponse }], isLoading: false } : msg
        ));
      }
    } catch (error: any) {
      console.error('Error from Gemini API:', error);
      let errorText = 'Sorry, I encountered an error. Please try again.';
      const isPermissionError = error.message?.toLowerCase().includes('permission') || error.message?.toLowerCase().includes('403');

      if (isPermissionError) {
        errorText = 'Permission Denied: This feature requires a paid API key from a Google Cloud Project with billing enabled.';
      }

      const errorMessage: Message = {
        id: generateUniqueId(),
        role: 'model',
        parts: [{ text: errorText }],
        timestamp: new Date(),
        isPermissionError: isPermissionError
      };
      setMessages(prev => prev.map(msg => msg.id === placeholderId ? errorMessage : msg));
    } finally {
      setIsLoading(false);
    }
  }, []);

  const handleSearchWithFilters = useCallback((filters: FilterCriteria) => {
    setIsFilterModalOpen(false);
    const userQuery = `Searching for doctors ${filters.specialty ? `specializing in ${filters.specialty}` : ''}...`;

    const userMessage: Message = { id: generateUniqueId(), role: 'user', parts: [{ text: userQuery }], timestamp: new Date() };
    const loadingMessageId = generateUniqueId();
    setMessages(prev => [...prev, userMessage, { id: loadingMessageId, role: 'model', parts: [{ text: '' }], timestamp: new Date(), isLoading: true }]);

    const performSearch = async (latitude: number | null, longitude: number | null) => {
        setIsLoading(true);
        try {
            const { doctors, groundingChunks } = await findDoctorsService(latitude, longitude, filters);
            if (doctors && doctors.length > 0) {
                setMessages(prev => prev.map(msg => msg.id === loadingMessageId ? {
                    id: generateUniqueId(),
                    role: 'model',
                    parts: [{ text: "Here are the top-rated healthcare providers I found:" }],
                    timestamp: new Date(),
                    doctors,
                    groundingChunks,
                } : msg));
            } else {
                 setMessages(prev => prev.map(msg => msg.id === loadingMessageId ? {
                    id: generateUniqueId(),
                    role: 'model',
                    parts: [{ text: "I couldn't find any specific doctors matching those filters. Try adjusting your search criteria." }],
                    timestamp: new Date(),
                } : msg));
            }
        } catch (error: any) {
            const isPermissionError = error.message?.toLowerCase().includes('permission');
            setMessages(prev => prev.map(msg => msg.id === loadingMessageId ? {
                id: generateUniqueId(),
                role: 'model',
                parts: [{ text: isPermissionError ? 'API Key Permission required for this search.' : 'Trouble searching for doctors.' }],
                timestamp: new Date(),
                isPermissionError
            } : msg));
        } finally {
            setIsLoading(false);
        }
    };

    if (filters.location) {
        performSearch(null, null);
    } else {
        navigator.geolocation.getCurrentPosition(
            (position) => performSearch(position.coords.latitude, position.coords.longitude),
            () => performSearch(null, null)
        );
    }
  }, []);

  const handleSuggestionSearch = useCallback(async (query: string) => {
    setIsSuggestionModalOpen(false);
    setIsLoading(true);
    const userMessage: Message = { id: generateUniqueId(), role: 'user', parts: [{ text: `Compare: ${query}` }], timestamp: new Date() };
    const loadingId = generateUniqueId();
    setMessages(prev => [...prev, userMessage, { id: loadingId, role: 'model', parts: [{ text: 'Generating high-res comparison...' }], timestamp: new Date(), isLoading: true }]);

    try {
      const { image, error } = await generateComparisonImage(query);
      if (image) {
        setMessages(prev => prev.map(msg => msg.id === loadingId ? {
          id: generateUniqueId(),
          role: 'model',
          parts: [{ text: `Comparison for ${query}` }],
          timestamp: new Date(),
          comparisonImage: image,
        } : msg));
      } else {
        throw new Error(error || 'Failed to generate image');
      }
    } catch (error: any) {
       const isPermissionError = error.message?.toLowerCase().includes('permission');
       setMessages(prev => prev.map(msg => msg.id === loadingId ? {
          id: generateUniqueId(),
          role: 'model',
          parts: [{ text: isPermissionError ? 'Advanced comparison requires a valid project API key with billing enabled.' : 'Failed to generate comparison.' }],
          timestamp: new Date(),
          isPermissionError
       } : msg));
    } finally {
      setIsLoading(false);
    }
  }, []);

  // Fix: Added handleTranslate to handle Assamese translation requests from ChatMessage
  const handleTranslate = useCallback(async (messageId: string, text: string) => {
    setMessages(prev => prev.map(msg => 
      msg.id === messageId ? { ...msg, isTranslating: true } : msg
    ));

    try {
      const translatedText = await translateToAssamese(text);
      setMessages(prev => prev.map(msg => 
        msg.id === messageId ? { ...msg, translatedText, isTranslating: false } : msg
      ));
    } catch (error: any) {
      console.error('Translation error:', error);
      setMessages(prev => prev.map(msg => 
        msg.id === messageId ? { ...msg, isTranslating: false } : msg
      ));
    }
  }, []);

  if (hasKey === false) {
    return (
      <div className="fixed inset-0 z-[200] bg-white flex flex-col items-center justify-center p-8 text-center">
        <div className="w-24 h-24 mb-6">
          <MascotIcon />
        </div>
        <h2 className="text-2xl font-extrabold text-slate-800 mb-4">API Key Required</h2>
        <p className="text-slate-600 mb-8 max-w-sm leading-relaxed">
          Medimart AI uses advanced Gemini models for medical vision and voice. To proceed, please select an API key from a <strong>paid GCP project</strong>.
          <br/><br/>
          <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="text-green-600 underline">Learn about billing</a>
        </p>
        <button 
          onClick={handleOpenKeySelector}
          className="px-10 py-4 bg-green-600 text-white rounded-2xl font-bold shadow-xl hover:bg-green-700 active:scale-95 transition-all flex items-center gap-3"
        >
          <KeyIcon className="w-6 h-6" />
          Select Project API Key
        </button>
      </div>
    );
  }

  return (
    <>
      <FilterModal isOpen={isFilterModalOpen} onClose={() => setIsFilterModalOpen(false)} onSearch={handleSearchWithFilters} />
      <SuggestionModal isOpen={isSuggestionModalOpen} onClose={() => setIsSuggestionModalOpen(false)} onSearch={handleSuggestionSearch} />
      {viewingImage && <ImageViewerModal src={viewingImage} onClose={() => setViewingImage(null)} />}
      {isVoiceAssistantOpen && <CameraVoiceAssistant onClose={() => setIsVoiceAssistantOpen(false)} />}

      <div className="flex flex-col h-[100dvh] font-sans overflow-hidden">
        <header className="p-3 md:p-4 flex items-center gap-3 sticky top-0 z-10 glassmorphism shrink-0">
          <div className="p-2 bg-gradient-to-br from-green-400 to-green-600 rounded-full shadow-lg">
            <SmileIcon className="w-6 h-6 md:w-8 md:h-8 text-white" />
          </div>
          <div className="flex-1">
            <h1 className="text-xl md:text-2xl font-extrabold text-slate-800 tracking-tight">Medimart AI</h1>
            <p className="text-xs md:text-sm text-green-600 font-semibold flex items-center">
              <span className="w-2 h-2 bg-green-500 rounded-full mr-1.5 animate-pulse"></span>
              Secure Connection
            </p>
          </div>
          <div className="flex gap-2">
            <button 
              onClick={handleOpenKeySelector}
              className="p-3 bg-white shadow-md rounded-full text-slate-500 hover:text-green-600 active:scale-95 transition-all neumorphic-convex border border-green-50"
              title="API Settings"
            >
              <KeyIcon className="w-5 h-5" />
            </button>
            <button 
              onClick={() => setIsVoiceAssistantOpen(true)}
              className="p-3 bg-green-600 shadow-md rounded-full text-white hover:bg-green-700 active:scale-95 transition-all border border-green-400"
              title="Voice Scan Assistant"
            >
              <CameraIcon className="w-5 h-5" />
            </button>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-3 md:p-6 space-y-6 md:space-y-8 pb-4">
          {messages.map((msg, index) => (
            <ChatMessage 
              key={msg.id || index} 
              message={msg} 
              isLoading={msg.isLoading}
              onTranslate={handleTranslate} 
              onImageView={setViewingImage}
              onFixKey={handleOpenKeySelector}
            />
          ))}
          <div ref={messagesEndRef} />
        </main>

        <footer className="p-2 sticky bottom-0 z-20 shrink-0 bg-white/30 backdrop-blur-md">
          <div className="max-w-4xl mx-auto space-y-2">
              <div className="grid grid-cols-2 gap-2 px-1">
                  <button onClick={() => setIsFilterModalOpen(true)} className="flex items-center justify-center px-3 py-3 text-sm font-bold text-slate-700 neumorphic-convex">
                      <MapPinIcon className="w-4 h-4 mr-1.5 text-green-500" />
                      Find Doctor
                  </button>
                  <button onClick={() => setIsSuggestionModalOpen(true)} className="flex items-center justify-center px-3 py-3 text-sm font-bold text-slate-700 neumorphic-convex">
                      <LightbulbIcon className="w-4 h-4 mr-1.5 text-yellow-500" />
                      Compare
                  </button>
              </div>
              <ChatInput onSend={handleSend} isLoading={isLoading} />
              <p className="text-[10px] md:text-xs text-center text-red-700 px-4 py-1 bg-red-50 rounded-lg mx-1">
                Advanced features require a paid API key for clinical-grade vision & voice.
              </p>
          </div>
        </footer>
      </div>
    </>
  );
};

